import os
import re
import subprocess
from google.cloud import storage
from typing import Dict, Any

# Allowlist of permitted ImageMagick operations
ALLOWED_OPERATIONS = {
    'resize', 'rotate', 'crop', 'quality', 'format', 
    'grayscale', 'blur', 'sharpen', 'brightness-contrast'
}

# Allowlist of permitted output formats
ALLOWED_FORMATS = {'jpg', 'jpeg', 'png', 'webp', 'gif'}

# Maximum dimension size to prevent resource exhaustion
MAX_DIMENSION = 10000

# Maximum file size (100MB)
MAX_FILE_SIZE = 100 * 1024 * 1024


def validate_filename(filename: str) -> bool:
    """Validate filename to prevent path traversal and command injection."""
    if not filename:
        return False
    
    # Check for path traversal attempts
    if '..' in filename or filename.startswith('/'):
        return False
    
    # Only allow alphanumeric, dash, underscore, and single dot for extension
    if not re.match(r'^[a-zA-Z0-9_-]+\.[a-zA-Z0-9]+$', filename):
        return False
    
    return True


def validate_dimension(value: str) -> bool:
    """Validate dimension values."""
    if not re.match(r'^\d+$', value):
        return False
    
    try:
        dim = int(value)
        return 0 < dim <= MAX_DIMENSION
    except ValueError:
        return False


def validate_percentage(value: str) -> bool:
    """Validate percentage values."""
    if not re.match(r'^\d+$', value):
        return False
    
    try:
        pct = int(value)
        return 0 <= pct <= 100
    except ValueError:
        return False


def validate_angle(value: str) -> bool:
    """Validate rotation angle."""
    if not re.match(r'^-?\d+$', value):
        return False
    
    try:
        angle = int(value)
        return -360 <= angle <= 360
    except ValueError:
        return False


def build_convert_command(input_path: str, output_path: str, options: Dict[str, Any]) -> list:
    """Build ImageMagick convert command with validated parameters."""
    command = ['convert', input_path]
    
    for operation, params in options.items():
        # Validate operation is in allowlist
        if operation not in ALLOWED_OPERATIONS:
            raise ValueError(f"Operation '{operation}' not allowed")
        
        if operation == 'resize':
            width = params.get('width', '')
            height = params.get('height', '')
            
            if width and not validate_dimension(width):
                raise ValueError("Invalid width dimension")
            if height and not validate_dimension(height):
                raise ValueError("Invalid height dimension")
            
            if width and height:
                command.extend(['-resize', f'{width}x{height}'])
            elif width:
                command.extend(['-resize', f'{width}'])
            elif height:
                command.extend(['-resize', f'x{height}'])
        
        elif operation == 'rotate':
            angle = params.get('angle', '')
            if not validate_angle(angle):
                raise ValueError("Invalid rotation angle")
            command.extend(['-rotate', angle])
        
        elif operation == 'crop':
            width = params.get('width', '')
            height = params.get('height', '')
            x = params.get('x', '0')
            y = params.get('y', '0')
            
            if not validate_dimension(width) or not validate_dimension(height):
                raise ValueError("Invalid crop dimensions")
            if not re.match(r'^\d+$', x) or not re.match(r'^\d+$', y):
                raise ValueError("Invalid crop coordinates")
            
            command.extend(['-crop', f'{width}x{height}+{x}+{y}'])
        
        elif operation == 'quality':
            quality = params.get('value', '')
            if not validate_percentage(quality):
                raise ValueError("Invalid quality value")
            command.extend(['-quality', quality])
        
        elif operation == 'grayscale':
            command.extend(['-colorspace', 'Gray'])
        
        elif operation == 'blur':
            radius = params.get('radius', '0')
            sigma = params.get('sigma', '1')
            if not re.match(r'^\d+$', radius) or not re.match(r'^\d+$', sigma):
                raise ValueError("Invalid blur parameters")
            command.extend(['-blur', f'{radius}x{sigma}'])
        
        elif operation == 'sharpen':
            radius = params.get('radius', '0')
            sigma = params.get('sigma', '1')
            if not re.match(r'^\d+$', radius) or not re.match(r'^\d+$', sigma):
                raise ValueError("Invalid sharpen parameters")
            command.extend(['-sharpen', f'{radius}x{sigma}'])
        
        elif operation == 'brightness-contrast':
            brightness = params.get('brightness', '0')
            contrast = params.get('contrast', '0')
            if not re.match(r'^-?\d+$', brightness) or not re.match(r'^-?\d+$', contrast):
                raise ValueError("Invalid brightness-contrast parameters")
            command.extend(['-brightness-contrast', f'{brightness}x{contrast}'])
    
    command.append(output_path)
    return command


def process_image(event: Dict[str, Any], context: Any) -> None:
    """Cloud Function triggered by Cloud Storage to convert images."""
    
    try:
        # Extract event data
        bucket_name = event['bucket']
        file_name = event['name']
        
        # Validate filename
        if not validate_filename(os.path.basename(file_name)):
            raise ValueError(f"Invalid filename: {file_name}")
        
        # Get conversion options from metadata
        storage_client = storage.Client()
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Check file size
        if blob.size > MAX_FILE_SIZE:
            raise ValueError(f"File size exceeds maximum allowed: {blob.size}")
        
        metadata = blob.metadata or {}
        
        # Extract and validate output format
        output_format = metadata.get('output_format', 'jpg').lower()
        if output_format not in ALLOWED_FORMATS:
            raise ValueError(f"Output format '{output_format}' not allowed")
        
        # Parse conversion options from metadata
        conversion_options = {}
        
        if 'resize_width' in metadata or 'resize_height' in metadata:
            conversion_options['resize'] = {
                'width': metadata.get('resize_width', ''),
                'height': metadata.get('resize_height', '')
            }
        
        if 'rotate_angle' in metadata:
            conversion_options['rotate'] = {'angle': metadata.get('rotate_angle')}
        
        if 'crop_width' in metadata and 'crop_height' in metadata:
            conversion_options['crop'] = {
                'width': metadata.get('crop_width'),
                'height': metadata.get('crop_height'),
                'x': metadata.get('crop_x', '0'),
                'y': metadata.get('crop_y', '0')
            }
        
        if 'quality' in metadata:
            conversion_options['quality'] = {'value': metadata.get('quality')}
        
        if metadata.get('grayscale') == 'true':
            conversion_options['grayscale'] = {}
        
        if 'blur_radius' in metadata:
            conversion_options['blur'] = {
                'radius': metadata.get('blur_radius', '0'),
                'sigma': metadata.get('blur_sigma', '1')
            }
        
        if 'sharpen_radius' in metadata:
            conversion_options['sharpen'] = {
                'radius': metadata.get('sharpen_radius', '0'),
                'sigma': metadata.get('sharpen_sigma', '1')
            }
        
        if 'brightness' in metadata or 'contrast' in metadata:
            conversion_options['brightness-contrast'] = {
                'brightness': metadata.get('brightness', '0'),
                'contrast': metadata.get('contrast', '0')
            }
        
        # Create secure temporary directory
        temp_dir = '/tmp'
        os.makedirs(temp_dir, exist_ok=True)
        
        # Generate safe filenames
        base_name = re.sub(r'[^a-zA-Z0-9_-]', '_', os.path.splitext(os.path.basename(file_name))[0])
        input_path = os.path.join(temp_dir, f'{base_name}_input')
        output_path = os.path.join(temp_dir, f'{base_name}_output.{output_format}')
        
        # Download input file
        blob.download_to_filename(input_path)
        
        # Build and execute convert command
        command = build_convert_command(input_path, output_path, conversion_options)
        
        # Execute with timeout and resource limits
        result = subprocess.call(
            command,
            timeout=300,  # 5 minute timeout
            env={'PATH': '/usr/bin:/bin'}  # Restricted PATH
        )
        
        if result != 0:
            raise RuntimeError(f"ImageMagick conversion failed with code {result}")
        
        # Upload converted file
        output_blob_name = f"converted/{base_name}.{output_format}"
        output_blob = bucket.blob(output_blob_name)
        output_blob.upload_from_filename(output_path)
        
        print(f"Successfully converted {file_name} to {output_blob_name}")
        
    except Exception as e:
        print(f"Error processing image: {str(e)}")
        raise
    
    finally:
        # Clean up temporary files
        for path in [input_path, output_path]:
            if 'path' in locals() and os.path.exists(path):
                os.remove(path)